post.description:
컨테이너에 파일을 추가합니다. multipart/form-data 또는 file_id로 전송 가능합니다.

### Python (httpx) - multipart 업로드
```python
import httpx

BASE_URL = 'https://{domain}/agent/a{idx}'
container_id = 'YOUR_CONTAINER_ID'
url = BASE_URL + f'/openai/containers/{container_id}/files'

with open('path/to/file.bin', 'rb') as f:
    res = httpx.post(url, files={'file': f}, timeout=60)

res.raise_for_status()
print(res.json())
```

### Python (httpx) - file_id 전송
```python
import httpx

BASE_URL = 'https://{domain}/agent/a{idx}'
container_id = 'YOUR_CONTAINER_ID'
url = BASE_URL + f'/openai/containers/{container_id}/files'
payload = {
    'file_id': 'YOUR_FILE_ID',
}

res = httpx.post(url, json=payload, timeout=60)
res.raise_for_status()
print(res.json())
```

### Node.js (node-fetch) - multipart 업로드
```js
import fetch from 'node-fetch';
import FormData from 'form-data';
import fs from 'node:fs';

async function main() {
  const BASE_URL = 'https://{domain}/agent/a{idx}';
  const containerId = 'YOUR_CONTAINER_ID';
  const url = BASE_URL + '/openai/containers/' + encodeURIComponent(containerId) + '/files';

  const form = new FormData();
  form.append('file', fs.createReadStream('path/to/file.bin'));

  const res = await fetch(url, {
    method: 'POST',
    body: form,
    headers: form.getHeaders(),
  });

  if (!res.ok) throw new Error(res.status + ' ' + (await res.text()));
  console.log(await res.json());
}

main();
```

